import { AppDataSource } from '../../data-source';
import { CommissaryItem } from '../../models/CommissaryItem';
import { CommissaryPurchase } from '../../models/CommissaryPurchase';
import { NotFoundError, ValidationError } from '../../utils/apiErrors';
import { AuditEventType, logAuditEvent } from '../../utils/auditLogger';
import { logger } from '../../utils/logger';
import { PaginatedResponse, PaginationOptions } from '../../utils/pagination';
import { emitToOrganization } from '../../websocket/websocketServer';
import { TenantService } from '../base/TenantService';

import { getTreasuryService, TreasuryService } from './TreasuryService';

// ==================== DTOs ====================

export interface CreateCommissaryItemDTO {
  name: string;
  description?: string;
  price: number;
  category: string;
  stock?: number;
  imageUrl?: string;
  metadata?: Record<string, unknown>;
}

export interface UpdateCommissaryItemDTO {
  name?: string;
  description?: string;
  price?: number;
  category?: string;
  stock?: number;
  isActive?: boolean;
  imageUrl?: string;
  metadata?: Record<string, unknown>;
}

export interface PurchaseItemDTO {
  itemId: string;
  quantity: number;
}

export interface CommissaryFilters {
  category?: string;
  activeOnly?: boolean;
  searchTerm?: string;
  sortBy?: string;
  sortOrder?: 'ASC' | 'DESC';
}

// ==================== SERVICE ====================

/**
 * CommissaryService
 *
 * Manages organization commissary items and purchases.
 * Purchases atomically decrement stock and deduct credits in a single transaction.
 */
export class CommissaryService extends TenantService<CommissaryItem> {
  private readonly purchaseRepo = AppDataSource.getRepository(CommissaryPurchase);
  private readonly treasuryService: TreasuryService;

  constructor() {
    super(AppDataSource.getRepository(CommissaryItem), {
      enableCache: true,
      cacheTTL: 300,
      cacheCheckPeriod: 60,
    });
    this.treasuryService = getTreasuryService();
  }

  // ==================== ITEM CRUD ====================

  async createItem(
    organizationId: string,
    creatorId: string,
    dto: CreateCommissaryItemDTO
  ): Promise<CommissaryItem> {
    const item = await this.create(organizationId, {
      name: dto.name,
      description: dto.description,
      price: dto.price,
      category: dto.category,
      stock: dto.stock ?? -1,
      imageUrl: dto.imageUrl,
      metadata: dto.metadata,
      createdBy: creatorId,
    });

    logAuditEvent({
      eventType: AuditEventType.SENSITIVE_DATA_ACCESS,
      userId: creatorId,
      resource: `commissary/${item.id}`,
      action: 'commissary_item_created',
      message: `Commissary item created: ${item.name} (${item.price})`,
      metadata: { organizationId, itemId: item.id },
    });

    logger.info('Commissary item created', { organizationId, itemId: item.id, name: item.name });
    return item;
  }

  async getItemById(organizationId: string, itemId: string): Promise<CommissaryItem | null> {
    return this.repository.findOne({
      where: { id: itemId, organizationId },
    });
  }

  async listItems(
    organizationId: string,
    pagination: PaginationOptions,
    filters?: CommissaryFilters
  ): Promise<PaginatedResponse<CommissaryItem>> {
    const qb = this.repository
      .createQueryBuilder('item')
      .where('item."organizationId" = :orgId', { orgId: organizationId });

    if (filters?.activeOnly !== false) {
      qb.andWhere('item."isActive" = true');
    }
    if (filters?.category) {
      qb.andWhere('item.category = :category', { category: filters.category });
    }
    if (filters?.searchTerm) {
      qb.andWhere('(item.name ILIKE :term OR item.description ILIKE :term)', {
        term: `%${filters.searchTerm}%`,
      });
    }

    let sortBy = 'item."createdAt"';
    if (filters?.sortBy === 'price') {
      sortBy = 'item.price';
    } else if (filters?.sortBy === 'name') {
      sortBy = 'item.name';
    }
    const sortOrder = filters?.sortOrder === 'ASC' ? 'ASC' : 'DESC';
    qb.orderBy(sortBy, sortOrder);

    const page = pagination.page ?? 1;
    const limit = pagination.limit ?? 20;
    qb.skip((page - 1) * limit).take(limit);

    const [data, total] = await qb.getManyAndCount();
    const totalPages = Math.ceil(total / limit);

    return {
      data,
      pagination: {
        page,
        limit,
        total,
        totalPages,
        hasNext: page < totalPages,
        hasPrev: page > 1,
      },
    };
  }

  async updateItem(
    organizationId: string,
    itemId: string,
    dto: UpdateCommissaryItemDTO
  ): Promise<CommissaryItem> {
    const item = await this.getItemById(organizationId, itemId);
    if (!item) {
      throw new NotFoundError('Commissary item');
    }

    if (dto.name !== undefined) {
      item.name = dto.name;
    }
    if (dto.description !== undefined) {
      item.description = dto.description;
    }
    if (dto.price !== undefined) {
      item.price = dto.price;
    }
    if (dto.category !== undefined) {
      item.category = dto.category;
    }
    if (dto.stock !== undefined) {
      item.stock = dto.stock;
    }
    if (dto.isActive !== undefined) {
      item.isActive = dto.isActive;
    }
    if (dto.imageUrl !== undefined) {
      item.imageUrl = dto.imageUrl;
    }
    if (dto.metadata !== undefined) {
      item.metadata = dto.metadata;
    }

    return this.repository.save(item);
  }

  async deleteItem(organizationId: string, itemId: string): Promise<void> {
    const item = await this.getItemById(organizationId, itemId);
    if (!item) {
      throw new NotFoundError('Commissary item');
    }
    await this.repository.remove(item);
    logger.info('Commissary item deleted', { organizationId, itemId });
  }

  // ==================== PURCHASES ====================

  /**
   * Purchase an item from the commissary.
   * Atomically: validate stock -> deduct credits -> decrement stock -> create purchase record.
   *
   * Strategy: Deduct credits first (in TreasuryService's own transaction), then
   * lock the item row and modify stock in a separate transaction. If the stock
   * transaction fails after credits have been deducted, we compensate by
   * refunding the credits. This avoids the two-transaction atomicity gap where
   * credits and stock modifications could diverge.
   */
  async purchaseItem(
    organizationId: string,
    buyerId: string,
    dto: PurchaseItemDTO
  ): Promise<CommissaryPurchase> {
    // Pre-flight check: verify item exists and is purchasable (no lock needed yet)
    const item = await this.repository.findOne({
      where: { id: dto.itemId, organizationId },
    });

    if (!item) {
      throw new NotFoundError('Commissary item');
    }
    if (!item.isActive) {
      throw new ValidationError('Item is no longer available');
    }
    if (item.stock !== -1 && item.stock < dto.quantity) {
      throw new ValidationError(
        `Insufficient stock. Available: ${item.stock}, Requested: ${dto.quantity}`
      );
    }

    const totalPrice = Number(item.price) * dto.quantity;

    // Step 1: Deduct credits (runs in TreasuryService's own transaction with SELECT FOR UPDATE).
    // If insufficient balance, this throws before any stock modification.
    const creditTxn = await this.treasuryService.spendCredits(organizationId, buyerId, {
      amount: totalPrice,
      purpose: `Commissary: ${item.name} x${dto.quantity}`,
      category: 'purchase',
      metadata: { itemId: item.id, itemName: item.name, quantity: dto.quantity },
    });

    // Step 2: Lock item row, decrement stock, create purchase record.
    // If this fails, compensate by refunding the credits.
    const queryRunner = AppDataSource.createQueryRunner();
    await queryRunner.connect();
    await queryRunner.startTransaction();

    try {
      // Re-check with pessimistic lock (stock may have changed since pre-flight)
      const lockedItem = await queryRunner.manager.findOne(CommissaryItem, {
        where: { id: dto.itemId, organizationId },
        lock: { mode: 'pessimistic_write' },
      });

      if (!lockedItem?.isActive) {
        throw new ValidationError('Item is no longer available');
      }
      if (lockedItem.stock !== -1 && lockedItem.stock < dto.quantity) {
        throw new ValidationError(
          `Insufficient stock. Available: ${lockedItem.stock}, Requested: ${dto.quantity}`
        );
      }

      // Decrement stock
      if (lockedItem.stock !== -1) {
        lockedItem.stock -= dto.quantity;
        await queryRunner.manager.save(lockedItem);
      }

      // Create purchase record linked to the credit transaction
      const purchase = queryRunner.manager.create(CommissaryPurchase, {
        organizationId,
        itemId: lockedItem.id,
        buyerId,
        quantity: dto.quantity,
        totalPrice,
        transactionId: creditTxn.id,
      } as Record<string, unknown>);
      const saved = await queryRunner.manager.save(purchase);

      await queryRunner.commitTransaction();

      logAuditEvent({
        eventType: AuditEventType.SENSITIVE_DATA_ACCESS,
        userId: buyerId,
        resource: `commissary/${lockedItem.id}/purchase/${saved.id}`,
        action: 'commissary_purchased',
        message: `Purchased ${dto.quantity}x ${lockedItem.name} for ${totalPrice}`,
        metadata: { organizationId, itemId: lockedItem.id, purchaseId: saved.id },
      });

      emitToOrganization(organizationId, 'commissary:purchased', {
        itemId: lockedItem.id,
        buyerId,
        quantity: dto.quantity,
        totalPrice,
      });

      logger.info('Commissary purchase completed', {
        organizationId,
        itemId: lockedItem.id,
        buyerId,
        quantity: dto.quantity,
        totalPrice,
      });

      return saved;
    } catch (error: unknown) {
      await queryRunner.rollbackTransaction();

      // Compensate: refund the credits that were already deducted
      try {
        await this.treasuryService.earnCredits(organizationId, 'system', {
          amount: totalPrice,
          source: `Refund: ${item.name} x${dto.quantity} (purchase failed)`,
          category: 'refund',
          metadata: {
            originalTransactionId: creditTxn.id,
            itemId: item.id,
            reason: String(error),
          },
        });
        logger.warn('Commissary purchase failed — credits refunded', {
          organizationId,
          itemId: item.id,
          amount: totalPrice,
        });
      } catch (refundError: unknown) {
        // Critical: refund failed — log for manual intervention
        logger.error('CRITICAL: Commissary refund failed — manual intervention required', {
          organizationId,
          buyerId,
          itemId: item.id,
          amount: totalPrice,
          originalTransactionId: creditTxn.id,
          refundError: String(refundError),
        });
      }

      throw error;
    } finally {
      await queryRunner.release();
    }
  }

  /**
   * Get purchase history for the organization or for a specific user.
   */
  async getPurchaseHistory(
    organizationId: string,
    pagination: PaginationOptions,
    buyerId?: string
  ): Promise<PaginatedResponse<CommissaryPurchase>> {
    const qb = this.purchaseRepo
      .createQueryBuilder('p')
      .leftJoinAndSelect('p.item', 'item')
      .where('p."organizationId" = :orgId', { orgId: organizationId });

    if (buyerId) {
      qb.andWhere('p."buyerId" = :buyerId', { buyerId });
    }

    qb.orderBy('p."createdAt"', 'DESC');

    const page = pagination.page ?? 1;
    const limit = pagination.limit ?? 20;
    qb.skip((page - 1) * limit).take(limit);

    const [data, total] = await qb.getManyAndCount();
    const totalPages = Math.ceil(total / limit);

    return {
      data,
      pagination: {
        page,
        limit,
        total,
        totalPages,
        hasNext: page < totalPages,
        hasPrev: page > 1,
      },
    };
  }
}

